(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH');
const sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});let rows=[],meta={},payloadRef=null;
function $(s){return document.querySelector(s)}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function appKey(){return meta.id||payloadRef?.version_id||meta.file_name||''}
function stateKey(){return 'doit-json:'+appKey()}
function manualKey(){return 'doit-manual-v1:'+appKey()}
function historyKey(){return 'doit-print-history-v1:'+appKey()}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value),receiver:T($('#storeSelect')?.value)}}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function manuals(){try{return JSON.parse(localStorage.getItem(manualKey())||'[]')}catch{return[]}}
function history(){try{return JSON.parse(localStorage.getItem(historyKey())||'[]')}catch{return[]}}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function pkFromData(x){if(x.poolKey)return x.poolKey;if(x.manual)return['MANUAL',x.id||'',x.store||'',x.brand||'',x.code||'',x.name||x.sku||'',x.type||''].join('|');const name=T(x.name||x.sku);return[x.brand||'',x.size||'',x.code||name,name,x.type||''].join('|')}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function recFromKey(k){return String(k).split('|')[3]||''}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function scopeRows(){const f=filters();return rows.filter(r=>!realTele(r)&&(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps))}
function manualInScope(){const f=filters();return manuals().filter(x=>(!f.start||x.start===f.start)&&(!f.end||x.end===f.end)&&(!f.ps||x.ps===f.ps)&&(!f.receiver||x.store===f.receiver))}
function add(map,k,n){map.set(k,(map.get(k)||0)+N(n))}
function addStore(stores,k,store,qty){store=T(store)||'ไม่ระบุร้าน';if(!stores.has(k))stores.set(k,new Map());const m=stores.get(k);m.set(store,(m.get(store)||0)+N(qty))}
function setLabel(labels,k,x){if(!labels.has(k))labels.set(k,{key:k,brand:T(x.brand),size:T(x.size),code:T(x.code),name:T(x.sku||x.name)||k,type:T(x.type),manual:!!x.manual})}
function build(){const f=filters(),order=new Map(),sent=new Map(),stores=new Map(),labels=new Map();scopeRows().forEach(r=>{const k=pk(r);add(order,k,r.qty);setLabel(labels,k,r)});history().forEach(h=>{if(h.start!==f.start||h.end!==f.end||h.ps!==f.ps)return;(h.items||[]).forEach(x=>{const k=pkFromData(x);add(sent,k,x.qty);addStore(stores,k,x.store||h.store,x.qty);setLabel(labels,k,{...x,sku:x.name||x.sku})})});const send=state().send||{};Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(key=>{const qty=N(send[key]);if(qty<=0)return;const k=pkFromKey(key),store=recFromKey(key);add(sent,k,qty);addStore(stores,k,store,qty)});manualInScope().forEach(x=>{const k=pkFromData({...x,manual:true});add(sent,k,x.qty);addStore(stores,k,x.store,x.qty);setLabel(labels,k,{...x,sku:x.name,manual:true})});const keys=new Set([...order.keys(),...sent.keys()]);return [...keys].map(k=>{const l=labels.get(k)||{key:k,name:k,brand:'',size:'',code:'',type:''};const keyed=N(order.get(k)),sentQty=N(sent.get(k)),remain=keyed-sentQty;const storeText=[...(stores.get(k)||new Map()).entries()].filter(([,q])=>N(q)).sort((a,b)=>sorter.compare(a[0],b[0])).map(([s,q])=>`${s} ${F(q)}`).join(', ');return{...l,keyed,sent:sentQty,stores:storeText||'-',remain}}).sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.name,b.name))}
function csv(data){const out=[['ชื่อสินค้า','จำนวนคีย์','ร้านที่ส่ง','ของเหลือ']];data.forEach(r=>out.push([r.name,r.keyed,r.stores,r.remain]));const blob='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([blob],{type:'text/csv;charset=utf-8'}));a.download='doit-remaining-summary-simple.csv';a.click()}
function css(){if($('#remainSummaryCss279'))return;const st=document.createElement('style');st.id='remainSummaryCss279';st.textContent='#remainOverlay{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:9998;display:flex;align-items:flex-end}#remainPanel{background:#fff;width:100%;max-height:88vh;border-radius:18px 18px 0 0;overflow:auto;color:#111827}#remainHead{position:sticky;top:0;background:#087b34;color:#fff;padding:10px 12px;display:flex;justify-content:space-between;gap:8px;align-items:center}#remainHead button{height:34px;border:1px solid #fff;background:#fff;color:#087b34;border-radius:8px;font-weight:900;padding:0 10px}.remainNote{padding:10px;color:#4b5563;font-size:12px}.remainWrap{overflow:auto;padding:0 10px 12px}.remainTbl{width:100%;border-collapse:collapse;min-width:760px;font-size:12px}.remainTbl th,.remainTbl td{border:1px solid #e5e7eb;padding:7px;text-align:center}.remainTbl th{background:#f8fafc}.remainTbl td:nth-child(1),.remainTbl th:nth-child(1),.remainTbl td:nth-child(3),.remainTbl th:nth-child(3){text-align:left}.remainNeg{color:#dc2626;font-weight:950}.remainPos{color:#111827;font-weight:900}.remainZero{color:#15803d;font-weight:900}@media(max-width:640px){.remainTbl{min-width:680px}}';document.head.appendChild(st)}
function openSummary(){css();$('#remainOverlay')?.remove();const data=build();const f=filters();const ov=document.createElement('div');ov.id='remainOverlay';ov.innerHTML=`<section id="remainPanel"><div id="remainHead"><div><b>สรุปของเหลือ</b><br><small>วันที่ ${esc(f.start)} - ${esc(f.end)} · PS ${esc(f.ps||'ทั้งหมด')} · ไม่รวม Telesale</small></div><span><button id="remainCsv">Export</button> <button id="remainClose">ปิด</button></span></div><div class="remainNote">ของเหลือ = จำนวนคีย์ - จำนวนที่ส่ง/ปิดบิล/ค้างส่ง. ถ้าส่งเกินจะแสดงติดลบสีแดง เช่น -1</div><div class="remainWrap"><table class="remainTbl"><thead><tr><th>ชื่อสินค้า</th><th>จำนวนคีย์</th><th>ร้านที่ส่ง</th><th>ของเหลือ</th></tr></thead><tbody>${data.map(r=>`<tr><td>${esc(r.name)}<br><small>${esc(r.code||'')}</small></td><td>${F(r.keyed)}</td><td>${esc(r.stores)}</td><td class="${r.remain<0?'remainNeg':(r.remain===0?'remainZero':'remainPos')}">${F(r.remain)}</td></tr>`).join('')||'<tr><td colspan="4">ไม่พบข้อมูล</td></tr>'}</tbody></table></div></section>`;document.body.appendChild(ov);$('#remainClose').onclick=()=>ov.remove();$('#remainCsv').onclick=()=>csv(data);ov.onclick=e=>{if(e.target===ov)ov.remove()}}
function install(){const a=document.querySelector('.actions');if(a&&!$('#remainSummaryBtn')){const b=document.createElement('button');b.id='remainSummaryBtn';b.type='button';b.className='outline';b.textContent='สรุปของเหลือ';b.onclick=openSummary;a.prepend(b)}}
function wrap(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__remain279)return false;const old=window.DOIT_JSON_APP.load.bind(window.DOIT_JSON_APP);window.DOIT_JSON_APP.load=(payload,m={})=>{payloadRef=payload;meta=m||{};rows=(payload.rows||payload||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));old(payload,m);setTimeout(install,120)};window.DOIT_JSON_APP.__remain279=true;return true}
function boot(){install();if(!wrap())setTimeout(boot,300)}document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();})();